# Resource Group artifact — creates a resource group in the target subscription at assignment
# Resource group artifacts are referenced by ARM template artifacts via the --resource-group flag.

MG_ID='alz-landing-zones'
BP_NAME='landing-zone-baseline'

# Resource Group placeholders are defined in the blueprint definition itself (not as separate artifacts)
# They appear in the 'resourceGroups' property of the blueprint definition.
# Update the blueprint definition to add/change resource group placeholders:
az blueprint update \
  --name $BP_NAME \
  --management-group $MG_ID \
  --resource-groups '{
    "rg-workloads": {
      "location": "[parameters(\"subscriptionLocation\")]",
      "metadata": {
        "displayName": "Workload resource group"
      }
    },
    "rg-monitoring": {
      "location": "[parameters(\"subscriptionLocation\")]",
      "tags": {
        "Purpose": "Monitoring"
      }
    }
  }'

# At assignment, the actual resource group names and locations are specified:
# --parameters includes resourceGroup overrides:
# The 'rg-workloads' placeholder resolves to the actual RG name in the target subscription.
az blueprint assignment create \
  --name 'assign-baseline' \
  --subscription '<sub-id>' \
  --blueprint-version '...' \
  --location eastus \
  --lock-mode AllResourcesDoNotDelete \
  --identity-type SystemAssigned \
  --resource-groups '{
    "rg-workloads": {"name": "rg-payments-prod-eastus", "location": "eastus"},
    "rg-monitoring": {"name": "rg-payments-monitoring-prod", "location": "eastus"}
  }' \
  --parameters '{
    "subscriptionLocation": {"value": "eastus"}
  }'
